import java.sql.*;

// PreparedStatementの作成と使用
String sql = "SELECT * FROM users WHERE age >= ? AND city = ?";
try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
    // パラメータのバインド（1始まり）
    pstmt.setInt(1, 20);           // 1番目の?
    pstmt.setString(2, "Tokyo");   // 2番目の?

    ResultSet rs = pstmt.executeQuery();
    while (rs.next()) {
        System.out.println(rs.getString("name"));
    }
}

// INSERT文でのPreparedStatement
String insertSql = "INSERT INTO users (name, age) VALUES (?, ?)";
try (PreparedStatement pstmt = conn.prepareStatement(insertSql)) {
    // 1件目
    pstmt.setString(1, "Taro");
    pstmt.setInt(2, 25);
    pstmt.executeUpdate();

    // 2件目（パラメータを再設定して再利用）
    pstmt.setString(1, "Hanako");
    pstmt.setInt(2, 30);
    pstmt.executeUpdate();
}

