// ★ 危険な例：文字列連結（SQLインジェクションの脆弱性）
String userInput = "'; DROP TABLE users; --";
String dangerousSql = "SELECT * FROM users WHERE name = '" 
    + userInput + "'"; 
// → SELECT * FROM users WHERE name = ''; DROP TABLE users; --'
// テーブルが削除される可能性がある！

// ★ 安全な例：PreparedStatement
