import java.sql.*;

try (Connection conn = DriverManager.getConnection(url, user, pw)) {
    // 自動コミットを無効化
    conn.setAutoCommit(false);

    try (Statement stmt = conn.createStatement()) {
        // 送金処理：Aから引き出し
        stmt.executeUpdate(
            "UPDATE accounts SET balance = balance - 10000 " +
            "WHERE name = 'A'");

        // 送金処理：Bに入金
        stmt.executeUpdate(
            "UPDATE accounts SET balance = balance + 10000 " +
            "WHERE name = 'B'");

        // すべて成功したらコミット
        conn.commit();
        System.out.println("送金完了");

    } catch (SQLException e) {
        // エラー時はロールバック
        conn.rollback();
        System.err.println("送金失敗、ロールバック実行");
        throw e;
    }
}

import java.sql.*;

try (Connection conn = DriverManager.getConnection(url, user, pw)) {
    conn.setAutoCommit(false);
    Statement stmt = conn.createStatement();

    // 操作1
    stmt.executeUpdate(
        "INSERT INTO logs (msg) VALUES ('操作1')");

    // Savepointを設定
    Savepoint sp = conn.setSavepoint("after_op1");

    try {
        // 操作2（失敗する可能性あり）
        stmt.executeUpdate(
            "INSERT INTO logs (msg) VALUES ('操作2')");
        // エラー発生！
        throw new SQLException("操作2でエラー");
    } catch (SQLException e) {
        // Savepointまでロールバック（操作1は保持される）
        conn.rollback(sp);
        System.out.println("操作2のみロールバック");
    }

    // 操作1のみコミット
    conn.commit();
}

